const DV2: CheckDigit = CheckDigit { weights: &[3, 2, 10, 9, 8, 7, 6, 5, 4, 3, 2], rule: Rule::RightmostDigit, remainder_to0: &[], multiply_by10: false, encode_x_at: 0, encode_zero_at: 0 };

